clc;
clear;
close all;

Am = 1;
fm = 500;
Ac = 5;
fc = 5000;
fs = 20*fc;

t = 0:1/fs:4/fm;

m = Am*sin(2*pi*fm*t);
c = Ac*sin(2*pi*fc*t);

mu = Am/Ac;

am = Ac*(1 + mu*sin(2*pi*fm*t)).*sin(2*pi*fc*t);

dem = abs(hilbert(am));
dem = dem - mean(dem);

N = length(am);
f = linspace(-fs/2, fs/2, N);
AM_FFT = abs(fftshift(fft(am)))/N;

USB = fc + fm;
LSB = fc - fm;

Pc = Ac^2/2;
Psb = (mu^2*Pc)/4;

figure('Name','AM Modulation','NumberTitle','off'); %[output:0578bd85]

subplot(3,2,1); %[output:0578bd85]
plot(t,m); %[output:0578bd85]
title('Message'); %[output:0578bd85]
grid on; %[output:0578bd85]

subplot(3,2,2); %[output:0578bd85]
plot(t,c); %[output:0578bd85]
title('Carrier'); %[output:0578bd85]
grid on; %[output:0578bd85]

subplot(3,2,3); %[output:0578bd85]
plot(t,am); %[output:0578bd85]
title('AM Signal'); %[output:0578bd85]
grid on; %[output:0578bd85]

subplot(3,2,4); %[output:0578bd85]
plot(t,dem); %[output:0578bd85]
title('Demodulated'); %[output:0578bd85]
grid on; %[output:0578bd85]

subplot(3,2,5); %[output:0578bd85]
plot(f,AM_FFT); %[output:0578bd85]
xlim([fc-3*fm fc+3*fm]); %[output:0578bd85]
title('Sidebands'); %[output:0578bd85]
grid on; %[output:0578bd85]

subplot(3,2,6); %[output:0578bd85]
bar([Pc Psb Psb]); %[output:0578bd85]
set(gca,'XTickLabel',{'Carrier','USB','LSB'}); %[output:0578bd85]
title('Power'); %[output:0578bd85]
grid on; %[output:0578bd85]

fprintf('mu = %.2f | USB = %d Hz | LSB = %d Hz | Pc = %.2f W | Psb = %.3f W\n', ... %[output:group:9a3f2d1d] %[output:95824890]
    mu, USB, LSB, Pc, Psb); %[output:group:9a3f2d1d] %[output:95824890]

